// gen_terraform reads a schema YAML file and generates Terraform provider
// resource registration code, writing the output to the specified Go file.
//
// Usage: go run scripts/gen_terraform/main.go <schema.yaml> <output.go>
//
// The generated file defines a ResourceGroup variable containing all operations
// from the schema, with automatic CRUD operation mapping. This follows the same
// pattern as gen_mcptools — one generated file per command group.
//
// This script is run in CI whenever the schema changes.
package main

import (
	"bytes"
	"fmt"
	"go/format"
	"os"
	"strings"
	"text/template"

	"github.com/FabianSchurig/bitbucket-cli/scripts/internal/spec"
)

// ─── Template data types ──────────────────────────────────────────────────────

type TFResourceData struct {
	SchemaPath  string
	VarName     string // e.g., "PRResourceGroup"
	TypeName    string // e.g., "pr"
	Description string
	Category    string // human-readable API group (e.g., "Pull Requests")
	Operations  []TFOpData
	CRUDCreate  string // OperationID or empty
	CRUDRead    string
	CRUDUpdate  string
	CRUDDelete  string
	CRUDList    string
}

type TFOpData struct {
	OperationID    string
	Method         string
	Path           string
	Summary        string
	Description    string
	Params         []TFParamData
	BodyFields     []TFBodyFieldData
	ResponseFields []TFBodyFieldData
	HasBody        bool
	Paginated      bool
	Scopes         []string
	DocURL         string
}

type TFParamData struct {
	Name     string
	In       string
	Type     string
	Required bool
}

type TFBodyFieldData struct {
	Path       string
	Type       string
	Desc       string
	IsArray    bool
	ItemFields []TFBodyFieldData
}

// ─── Template ─────────────────────────────────────────────────────────────────

const fileTemplate = `// Code generated by scripts/gen_terraform/main.go DO NOT EDIT.
// Source: {{.SchemaPath}}
//
// This file is regenerated whenever the schema changes in CI.
// Do not edit manually — run: go run scripts/gen_terraform/main.go {{.SchemaPath}} <output.go>

package tfprovider

func init() {
	RegisterResourceGroup({{.VarName}})
}

// {{.VarName}} contains the Terraform resource definition for the "{{.TypeName}}" resource group.
var {{.VarName}} = ResourceGroup{
	TypeName:    {{goStringLit .TypeName}},
	Description: {{goStringLit .Description}},
	Category:    {{goStringLit .Category}},
	Ops: MapCRUDOps({{goStringLit .TypeName}}, []OperationDef{
{{- range .Operations}}
		{
			OperationID: {{goStringLit .OperationID}},
			Method:      {{goStringLit .Method}},
			Path:        {{goStringLit .Path}},
			Summary:     {{goStringLit .Summary}},
			Description: {{goStringLit .Description}},
			Params: []ParamDef{
{{- range .Params}}
				{Name: {{goStringLit .Name}}, In: {{goStringLit .In}}, Type: {{goStringLit .Type}}, Required: {{.Required}}},
{{- end}}
			},
			BodyFields: []BodyFieldDef{
{{- range .BodyFields}}
				{{bodyFieldLit .}},
{{- end}}
			},
			ResponseFields: []BodyFieldDef{
{{- range .ResponseFields}}
				{{bodyFieldLit .}},
{{- end}}
			},
			HasBody:   {{.HasBody}},
			Paginated: {{.Paginated}},
{{- if .Scopes}}
			Scopes: []string{
{{- range .Scopes}}
				{{goStringLit .}},
{{- end}}
			},
{{- end}}
{{- if .DocURL}}
			DocURL: {{goStringLit .DocURL}},
{{- end}}
		},
{{- end}}
	}),
	AllOps: []OperationDef{
{{- range .Operations}}
		{
			OperationID: {{goStringLit .OperationID}},
			Method:      {{goStringLit .Method}},
			Path:        {{goStringLit .Path}},
			Summary:     {{goStringLit .Summary}},
			Description: {{goStringLit .Description}},
			Params: []ParamDef{
{{- range .Params}}
				{Name: {{goStringLit .Name}}, In: {{goStringLit .In}}, Type: {{goStringLit .Type}}, Required: {{.Required}}},
{{- end}}
			},
			BodyFields: []BodyFieldDef{
{{- range .BodyFields}}
				{{bodyFieldLit .}},
{{- end}}
			},
			ResponseFields: []BodyFieldDef{
{{- range .ResponseFields}}
				{{bodyFieldLit .}},
{{- end}}
			},
			HasBody:   {{.HasBody}},
			Paginated: {{.Paginated}},
{{- if .Scopes}}
			Scopes: []string{
{{- range .Scopes}}
				{{goStringLit .}},
{{- end}}
			},
{{- end}}
{{- if .DocURL}}
			DocURL: {{goStringLit .DocURL}},
{{- end}}
		},
{{- end}}
	},
}
`

// ─── Template functions ───────────────────────────────────────────────────────

var templateFuncMap = template.FuncMap{
	"goStringLit":  spec.GoStringLit,
	"bodyFieldLit": bodyFieldLit,
}

// bodyFieldLit renders a BodyFieldDef Go literal, including nested ItemFields.
func bodyFieldLit(bf TFBodyFieldData) string {
	return renderBodyFieldDef(bf, "\t\t\t\t")
}

func renderBodyFieldDef(bf TFBodyFieldData, indent string) string {
	var sb strings.Builder
	sb.WriteString("{")
	fmt.Fprintf(&sb, "Path: %s, Type: %s, Desc: %s", spec.GoStringLit(bf.Path), spec.GoStringLit(bf.Type), spec.GoStringLit(bf.Desc))
	if bf.IsArray {
		sb.WriteString(", IsArray: true")
		if len(bf.ItemFields) > 0 {
			sb.WriteString(", ItemFields: []BodyFieldDef{")
			for _, item := range bf.ItemFields {
				sb.WriteString("\n" + indent + "\t")
				sb.WriteString(renderBodyFieldDef(item, indent+"\t"))
				sb.WriteString(",")
			}
			sb.WriteString("\n" + indent + "}")
		}
	}
	sb.WriteString("}")
	return sb.String()
}

// ─── Conversion ───────────────────────────────────────────────────────────────

func operationToTFOp(op spec.OperationDef) TFOpData {
	params := make([]TFParamData, 0, len(op.Params))
	for _, p := range op.Params {
		params = append(params, TFParamData{
			Name:     p.Name,
			In:       p.In,
			Type:     p.Type,
			Required: p.Required,
		})
	}

	bodyFields := make([]TFBodyFieldData, 0, len(op.BodyFields))
	for _, bf := range op.BodyFields {
		bodyFields = append(bodyFields, specFieldToTFField(bf))
	}

	responseFields := make([]TFBodyFieldData, 0, len(op.ResponseFields))
	for _, rf := range op.ResponseFields {
		responseFields = append(responseFields, specFieldToTFField(rf))
	}

	return TFOpData{
		OperationID:    op.OperationID,
		Method:         op.Method,
		Path:           op.Path,
		Summary:        op.Summary,
		Description:    op.Description,
		Params:         params,
		BodyFields:     bodyFields,
		ResponseFields: responseFields,
		HasBody:        op.HasBody,
		Paginated:      op.Paginated,
		Scopes:         op.Scopes,
		DocURL:         op.DocURL,
	}
}

func buildDescription(cmdShort string, operations []TFOpData) string {
	var sb strings.Builder
	sb.WriteString(cmdShort)
	sb.WriteString("\n\nAvailable operations:\n")
	for _, op := range operations {
		desc := op.Summary
		if desc == "" {
			desc = op.OperationID
		}
		fmt.Fprintf(&sb, "- %s: %s [%s]\n", op.OperationID, desc, op.Method)
	}
	return sb.String()
}

// specFieldToTFField converts a spec.BodyField to a TFBodyFieldData,
// including nested array item fields.
func specFieldToTFField(bf spec.BodyField) TFBodyFieldData {
	tf := TFBodyFieldData{
		Path:    bf.Path,
		Type:    bf.GoType,
		Desc:    bf.Desc,
		IsArray: bf.IsArray,
	}
	for _, item := range bf.ItemFields {
		tf.ItemFields = append(tf.ItemFields, specFieldToTFField(item))
	}
	return tf
}

// ─── Main ─────────────────────────────────────────────────────────────────────

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <schema.yaml> <output.go>\n", os.Args[0])
		os.Exit(1)
	}

	schemaPath := os.Args[1]
	outputPath := os.Args[2]

	schema, err := spec.LoadSchema(schemaPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "%v\n", err)
		os.Exit(1)
	}

	cmdName, cmdUse, cmdShort, _ := spec.CommandMeta(schema.Info)
	category := spec.CommandCategory(schema.Info)

	operations := spec.BuildOperations(schema)
	tfOps := make([]TFOpData, 0, len(operations))
	for _, op := range operations {
		tfOps = append(tfOps, operationToTFOp(op))
	}

	data := TFResourceData{
		SchemaPath:  schemaPath,
		VarName:     cmdName + "ResourceGroup",
		TypeName:    cmdUse,
		Description: buildDescription(cmdShort, tfOps),
		Category:    category,
		Operations:  tfOps,
	}

	tmpl, err := template.New("terraform").Funcs(templateFuncMap).Parse(fileTemplate)
	if err != nil {
		fmt.Fprintf(os.Stderr, "parsing template: %v\n", err)
		os.Exit(1)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		fmt.Fprintf(os.Stderr, "executing template: %v\n", err)
		os.Exit(1)
	}

	formatted, err := format.Source(buf.Bytes())
	if err != nil {
		fmt.Fprintf(os.Stderr, "formatting generated code: %v\n", err)
		fmt.Fprintf(os.Stderr, "raw output:\n%s\n", buf.String())
		os.Exit(1)
	}

	if err := os.WriteFile(outputPath, formatted, 0o644); err != nil {
		fmt.Fprintf(os.Stderr, "writing output file: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Generated Terraform resource %q with %d operations → %s\n", data.TypeName, len(data.Operations), outputPath)
}
